# Perl Script: Haversine Distance Calculator

This script calculates the distance between two locations using the Haversine formula. It accepts latitude and longitude inputs for two locations, handles errors, and provides the result in kilometers or miles.

## Features
- Accepts latitude and longitude as command-line arguments.
- Calculates distance using the Haversine formula.
- Supports both kilometers and miles.
- Handles invalid inputs and unavailable location data.
- Includes tests and examples.

---

### Perl Script: `haversine_distance.pl`

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use JSON;
use URI::Escape;

# Script: haversine_distance.pl
# Purpose: Calculate the distance between two locations using the Haversine formula.
# Author: [Your Name]
# Date: [Date]

# Constants
my $KILOMETERS = 1;
my $MILES = 1;

# Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371; # Earth radius in kilometers

    # Convert latitude and longitude from degrees to radians
    my $lat1_rad = radian($lat1);
    my $lon1_rad = radian($lon1);
    my $lat2_rad = radian($lat2);
    my $lon2_rad = radian($lon2);

    # Haversine formula
    my $a = sin($lat1_rad - $lat2_rad) ** 2 +
           cos($lat1_rad) * cos($lat2_rad) * sin($lat1_rad - $lat2_rad) ** 2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $d = $R * $c;

    return $d;
}

# Convert degrees to radians
sub radians {
    my ($degrees) = @_;
    return $degrees * (pi() / 180);
}

# Helper function to get location names
sub get_location_name {
    my ($lat, $lon) = @_;
    my $url = "https://api.openstreetmap.org/api/0.6/map/search?lat=$lat&lon=$lon&limit=1";
    my $response = get($url);
    if ($response =~ /<name>(.*)<\/name>/) {
        return $1;
    } else {
        return "Location not found";
    }
}

# Main function
sub main {
    my $usage = "Usage: $0 --lat1 <lat1> --lon1 <lon1> --lat2 <lat2> --lon2 <lon2> --unit <km|miles>";
    my ($lat1, $lon1, $lat2, $lon2, $unit) = @ARGV;

    # Parse command-line arguments
    my ($lat1, $lon1, $lat2, $lon2, $unit);
    GetOptions(
        "lat1=s" => \$lat1,
        "lon1=s" => \$lon1,
        "lat2=s" => \$lat2,
        "lon2=s" => \$lon2,
        "unit=s" => \$unit
    ) or die $usage;

    # Validate inputs
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Missing required arguments: lat1, lon1, lat2, lon2";
    }

    # Validate unit
    if ($unit !~ /^km$/i && $unit !~ /^miles$/i) {
        die "Invalid unit: $unit. Must be km or miles";
    }

    # Calculate distance
    my $distance = haversine_distance($lat1, $lon1, $lat2, $lon2);
    my $unit_str = $unit eq 'km' ? 'km' : 'miles';

    # Get location names
    my $loc1 = get_location_name($lat1, $lon1);
    my $loc2 = get_location_name($lat2, $lon2);

    # Output result
    print "Distance between $loc1 and $loc2: $distance $unit_str\n";
}

# Helper function to get data from URL
sub get {
    my ($url) = @_;
    my $response = get($url);
    return $response;
}

# Example usage
main();
```

